import React from 'react';
import logo_oswc from '../../assets/oswclogo.PNG';
import ReactPlayer from 'react-player'
import OSWCH1VIDEO from '../../assets/video/oswc_h1_jude.mp4'

const Landing_bio = () => {
  return (
    <div className="bio_section">
      <div className='bio_section_details'>
        <div className="bio_section_details_p">
          <h3><strong><em>Who are we?</em></strong></h3>
          <br/>
          <p>We are current and former sex workers from Oregon and around the world. Some of us have been arrested or targeted by law enforcement, and some of us live and work in safer, decriminalized places like New Zealand. Some of us have always worked consensually under capitalism, others have survived pimps or trafficking. We welcome all people who support decriminalization and harm reduction in sex work, to get involved in our policy, education and networking-focused committee.
          <br/>
          <span className='bio_section_details_p_span_tab'/>
          <br />
          The OSWC is a registered 501(c) 3 non profit organization, which prioritizes hiring and leadership of sex workers, and welcomes allies and supporters to witness events, network and build community support, or get involved in direct actions.
          <br />
          <span className='bio_section_details_p_span_tab'/>
          <br/>
          Our current fiscal sponsor is <em>Woodhull Freedom Foundation.</em>
          <br />
          <div className='bio_section_details_p_logo'>
            <img src={logo_oswc}/>
          </div>

          </p>
        </div>
        <ReactPlayer className='bio_section_details_v' controls={true} url={OSWCH1VIDEO} />
      </div>
    </div>

  );
};

export default Landing_bio;
