import React from 'react';
import logo from '../../assets/oswclogo.PNG'
import '../../scss/main.scss'
import {
  Collapse,
  Navbar,
  NavbarToggler,
  NavbarBrand,
  Nav,
  NavItem,
  NavLink} from 'reactstrap';

export default class Nav_Bar extends React.Component {
  constructor(props) {
    super(props);

    this.toggle = this.toggle.bind(this);
    this.state = {
      isOpen: false
    };
  }
  toggle() {
    this.setState({
      isOpen: !this.state.isOpen
    });
  }
  render() {
    return (
      <div className="nav-container-div">
        <Navbar className="sticky-top "  expand="md">
          <NavbarBrand href="/#"><img className='logo-oswc' alt="logo" src={logo}/></NavbarBrand>
          <NavbarToggler onClick={this.toggle} />
          <Collapse isOpen={this.state.isOpen} navbar>
            <Nav className="parent-nav" navbar>
              <NavItem>
                <NavLink  href="/">Home</NavLink>
              </NavItem>
              <NavItem>
                <NavLink href="/#/about">About</NavLink>
              </NavItem>
              <NavItem>
                <NavLink href="/#/resources">Resources</NavLink>
              </NavItem>
              <NavItem>
                <NavLink href="https://donorbox.org/oswc-human-rights-committee">Donate</NavLink>
              </NavItem>
            </Nav>
          </Collapse>
        </Navbar>
      </div>
    );
  }
}