import React from 'react';
import { UncontrolledCarousel } from 'reactstrap';
import slide_2_image from '../../assets/mslide2.png';
import slide_3_image from '../../assets/mslide3.png';
import slide_4_image from '../../assets/mslide4.png';
import slide_5_image from '../../assets/mslide5.png';
import slide_6_image from '../../assets/mslide6.png';
import slide_8_image from '../../assets/mslide8.png';

const items = [

  {
    src: slide_2_image,
    altText: 'Slide 2',

  },
  {
    src: slide_3_image,
    altText: 'Slide 3',
   
  },
    {
    src: slide_4_image,
    altText: 'Slide 4',
  },
    {
    src: slide_5_image,
    altText: 'Slide 5',
  },
  {
    src: slide_6_image,
    altText: 'Slide 6',
  },
  {
    src: slide_8_image,
    altText: 'Slide 8',
   
  }
];

const Carousel2 = () => {
  return (
    <div className="container-carousel">
      <UncontrolledCarousel items={items} />
    </div>
    
  )
};

export default Carousel2;