import React from 'react';
import { Card, CardImg, CardText, CardBody,
  CardTitle, Button } from 'reactstrap';

const Card_template = ({ item }) => {
 
  if (item.pic == "") {
    
  }
  return (
      <div className="article_item_video grow">
        <a href={item.link}>

        {item.pic === "" ?
        <iframe
        className='article_item_video_image'
        width="100%"
        height="350"
        src={`https://www.youtube.com/embed/${item.embedId}`}
        frameBorder="0"
        allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
        allowFullScreen
        title="Embedded youtube"
        />
        :
        
        <img className='article_item_video_image'                                                                                                                  width="100%" src={item.pic} alt="Card image cap" />}
        <div>
          <hr/>
          <h4><strong>{item.title}</strong></h4>
        
        </div>
        </a>
      </div>
      
  );
};

export default Card_template;