import React from 'react';
import Carousel2 from '../carousel2';
import OSWCH2VIDEO from '../../assets/video/oswc_h2_prev.mp4';
import { Card, CardBody, CardText, CardTitle } from 'reactstrap';


const About_bio_section = () => {
  return (
    <div className='about_bio_section'>
      <div className='about_bio_section_bottom'>
        <div className='about_bio_section_bottom_1'>
          <p>In <u>January 2021</u>, Representative Rob Nosse sponsored a bill that called for decriminalization of sex work laws, called HB3088. Local advocates and sex workers found each other through social media and in-person networks and formed a small group that was determined to help support HB3088.</p> 
          <br></br>
          <p>The bill was largely unsupported in the Salem legislature, but the OSWC was granted one brief hearing for HB3088, but the bill died in session partly due to lack of support by legislators.</p>
          <br></br>
          <p>In <u>May 2021</u>, an anonymous donor made a large contribution to the OSWC, which allowed us to host our first Human Rights Commission event in Portland, Oregon on <u>July 15th</u>. For over three hours, attendees learned how the current partial-or-full criminalization of sex workers and their clients makes it harder to address victimization, creates underground markets and increases the opportunity for predatory individuals to commit abuses against the most marginalized people in societies.</p>
          <br></br>
        </div>
        <div className='about_bio_section_bottom_2'>
          <p>After investigating local arrests in Portland that were improperly labeled as “sex trafficking” by the media and Portland Police Bureau, the OSWC mobilized and testified for six consecutive weeks to Multnomah County Commissioners to raise awareness of this human rights violation and misuse of funds. OSWC Co-Chair Elle Stanger and other sex workers testified to a Portland City Council to end funding of decoy stings, on <u>November 10th, 2021</u>.</p>
          <br></br>
          <p>Johns Hopkins University hosted “Possibilities and Priorities for Marginalized Sex Workers”, moderated by OSWC Co-Chair Bianca Beebe in <u>November, 2021</u>.</p>
          <br></br>
          <Card className="socials_card">
            <Card>
              <CardBody>
                <CardTitle className="socials_card_title">Connect with us</CardTitle>
                <CardText className="socials_card_body">
                  <a href='https://www.instagram.com/oswcgroup/' className='socials_card_icon'>
                    <ion-icon name="logo-instagram"></ion-icon>
                  </a> 
                  <a href='https://twitter.com/orsexworkers' className='socials_card_icon'>
                    <ion-icon name="logo-twitter"></ion-icon>
                  </a> 
                </CardText>
                <CardText>Questions or concerns? Contact us at oswc_outreach@proton.me</CardText>
              </CardBody>
            </Card>
          </Card>

        </div> 
      </div>
      {/* <div className='about_bio_section_bottom'> */}
          <div className='about_bio_section_bottom_1'>
              <video src={OSWCH2VIDEO} width="100%" controls="controls" autoplay="false"/>
              <h4><strong>Our 2nd Human Rights Commission Event at University of Oregon’s Gerlinger Hall</strong></h4>
              <p>
                hosted speakers with lived experience in human trafficking, survival sex work, and public health experts and anti-trafficking organizers. You can view footage on Youtube, begin video at 28:51.
              </p>
              <br></br>
          </div>
      {/* </div>  */}
    </div>
   
   
  );
};
export default About_bio_section;